package main
import("bufio";"fmt";"os";"sort";"unicode")
func check(s string)int{n:=len(s);lower,upper,digit:=false,false,false;for _,c:=range s{if unicode.IsLower(c){lower=true};if unicode.IsUpper(c){upper=true};if unicode.IsDigit(c){digit=true}};missing:=0;if !lower{missing++};if !upper{missing++};if !digit{missing++};runs:=[]int{};for i:=0;i<n;{j:=i;for j<n&&s[j]==s[i]{j++};if j-i>=3{runs=append(runs,j-i)};i=j};if n<6{if missing>6-n{return missing};return 6-n};rep:=0;for _,r:=range runs{rep+=r/3};if n<=20{if missing>rep{return missing};return rep};del:=n-20;rem:=del;sort.Slice(runs,func(i,j int)bool{return runs[i]%3<runs[j]%3});for i,r:=range runs{if rem<=0{break};need:=r%3+1;use:=need;if rem<use{use=rem};runs[i]-=use;rem-=use};if rem>0{for i,r:=range runs{if rem<=0{break};use:=r-2;if use<0{use=0};if rem<use{use=rem};runs[i]-=use;rem-=use}};rep=0;for _,r:=range runs{if r>0{rep+=r/3}};if missing>rep{return del+missing};return del+rep}
func main(){in:=bufio.NewReader(os.Stdin);out:=bufio.NewWriter(os.Stdout);defer out.Flush();var t int;if _,e:=fmt.Fscan(in,&t);e!=nil{return};for tc:=0;tc<t;tc++{var s string;fmt.Fscan(in,&s);if tc>0{fmt.Fprintln(out);fmt.Fprintln(out)};fmt.Fprint(out,check(s))}}
